const pos = world.getPosition(bot);
const cx = Math.floor(pos.x);
const cy = Math.floor(pos.y);
const cz = Math.floor(pos.z);
// Green stem
for (let y = 0; y < 8; y++) {
  await skills.placeBlockFast(bot, 'green_concrete', cx, cy+y, cz);
}
// Pink petals (circle around top)
const petals = [[2,0],[0,2],[-2,0],[0,-2],[1,1],[-1,1],[1,-1],[-1,-1]];
for (const [dx,dz] of petals) {
  await skills.placeBlockFast(bot, 'pink_concrete', cx+dx, cy+8, cz+dz);
}
// Yellow center
await skills.placeBlockFast(bot, 'yellow_concrete', cx, cy+8, cz);
await skills.placeBlockFast(bot, 'yellow_concrete', cx, cy+9, cz);
// Leaves
await skills.placeBlockFast(bot, 'oak_leaves', cx+1, cy+4, cz);
await skills.placeBlockFast(bot, 'oak_leaves', cx-1, cy+5, cz);
log(bot, 'Giant flower built!');
```

```
const pos = world.getPosition(bot);
const cx = Math.floor(pos.x);
const cy = Math.floor(pos.y);
const cz = Math.floor(pos.z);
// Castle walls
await skills.fillBlocks(bot, 'stone_bricks', cx, cy, cz, cx+12, cy+8, cz+12, 'hollow');
// Floor
await skills.fillBlocks(bot, 'red_carpet', cx+1, cy, cz+1, cx+11, cy, cz+11);
// 4 corner towers
for (const [tx,tz] of [[cx,cz],[cx+12,cz],[cx,cz+12],[cx+12,cz+12]]) {
  await skills.buildCylinder(bot, 'stone_bricks', tx, cy, tz, 2, 12);
  await skills.placeBlockFast(bot, 'red_banner[rotation=0]', tx, cy+12, tz);
}
// Gate
await skills.fillBlocks(bot, 'air', cx+5, cy+1, cz, cx+7, cy+4, cz);
// Inside: throne
await skills.placeBlockFast(bot, 'gold_block', cx+6, cy+1, cz+10);
await skills.placeBlockFast(bot, 'oak_stairs[facing=south]', cx+6, cy+2, cz+10);
// Lanterns
for (let lx = cx+3; lx <= cx+9; lx += 3) {
  await skills.placeBlockFast(bot, 'lantern', lx, cy+7, cz+6);
}
log(bot, 'Castle built!');
```
